                    if (!verificationStatus)
                        return;

                    auto deviceKeys = cache::userKeys(local_user.to_string());
                    std::string sender_device_id;
                    if (deviceKeys) {
                        for (auto &[dev, key] : deviceKeys->device_keys) {
                            if (key.keys["curve25519:" + dev] == msg.sender_key) {
                                sender_device_id = dev;
                                break;
                            }
                        }
                    }

